SELECT COUNT(jurisdiction_id) 
FROM jurisdictions 
WHERE population_density > (SELECT AVG(population_density) FROM jurisdictions);

SELECT SUM(fully_vaccinated) AS total_fully_vaccinated
FROM vaccination_data
WHERE jurisdiction_id = 0;

SELECT AVG(COALESCE(v.fully_vaccinated, 0)) AS average_fully_vaccinated
FROM vaccination_data v
WHERE v.fully_vaccinated IS NOT NULL;
